}

double closestPair(std::vector<Point> const& points) {
	int rank, size;
	MPI_Comm_rank(MPI_COMM_WORLD, &rank);
	MPI_Comm_size(MPI_COMM_WORLD, &size);

	// Divide the points among ranks
	std::vector<int> counts(size), displs(size);
	int total_points = points.size();
	for (int i = 0; i < size; ++i) {
		counts[i] = std::ceil(static_cast<double>(total_points) / size);
		displs[i] = (i == 0 ? 0 : displs[i-1]) + counts[i-1];
	}
	std::vector<Point> local_points(counts[rank]);
	MPI_Scatterv(&points[0], &counts[0], &displs[0], MPI_POINT, 
	             &local_points[0], counts[rank], MPI_POINT, 0, MPI_COMM_WORLD);

	// Compute the closest pair distance locally
	double min_dist = std::numeric_limits<double>::max();
	for (int i = 0; i < local_points.size(); ++i) {
		for (int j = i + 1; j < local_points.size(); ++j) {
			double dist = distance(local_points[i], local_points[j]);
			if (dist < min_dist) min_dist = dist;
		}
	}

	// Gather and combine results from all ranks
	MPI_Allreduce(MPI_IN_PLACE, &min_dist, 1, MPI_DOUBLE, MPI_MIN, MPI_COMM_WORLD);

	return min_dist;
}
