		for (int j = i + 1; j < end; ++j) {
			double dist = distance(points[i], points[j]);
			if (dist < minDist) {
				minDist = dist;
			}
		}
	}

	return minDist;
}

// Function to find the closest pair of points in a vector using MPI
double closestPair(std::vector<Point> const& points) {
	int numRanks, rank;
	MPI_Comm_size(MPI_COMM_WORLD, &numRanks);
	MPI_Comm_rank(MPI_COMM_WORLD, &rank);

	if (rank == 0) {
		// Calculate the number of points per process
		int numPointsPerRank = points.size() / numRanks;

		// Create a vector to store the minimum distances found by each process
		std::vector<double> minDists(numRanks, INFINITY);

		// Send the subset of points to each process
		for (int i = 1; i < numRanks; ++i) {
			int start = i * numPointsPerRank;
			int end = std::min((i + 1) * numPointsPerRank, static_cast<int>(points.size()));
			MPI_Send(&start, 1, MPI_INT, i, 0, MPI_COMM_WORLD);
			MPI_Send(&end, 1, MPI_INT, i, 0, MPI_COMM_WORLD);
			MPI_Send(points.data() + start, end - start, MPI_DOUBLE, i, 0, MPI_COMM_WORLD);
		}

		// Receive the minimum distances found by each process
		for (int i = 1; i < numRanks; ++i) {
			int start;
			MPI_Recv(&start, 1, MPI_INT, i, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
			double minDist;
			MPI_Recv(&minDist, 1, MPI_DOUBLE, i, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
			minDists[i - 1] = minDist;
		}

		// Find the minimum distance among all processes
		double minDist = INFINITY;
		for (int i = 0; i < numRanks; ++i) {
			if (minDists[i] < minDist) {
				minDist = minDists[i];
			}
		}

		return minDist;
	} else {
		// Receive the subset of points from rank 0
		int start, end;
		MPI_Recv(&start, 1, MPI_INT, 0, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
		MPI_Recv(&end, 1, MPI_INT, 0, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);

		// Find the minimum distance among the subset of points
		double minDist = closestPairSubset(points, start, end);

		// Send the minimum distance back to rank 0
		MPI_Send(&minDist, 1, MPI_DOUBLE, 0, 0, MPI_COMM_WORLD);

		return INFINITY;
	}
